187	const InputMode = enum(u8) {
188	    // By pass Vietnamese input processing and append the character as is.
189	    literal,
190	    // Process Vietnamese input in Telex input method.
191	    telex,
192	};
193	
194	const State = extern struct {
195	    // The effective buffer to process Vietnamese input. we will skip processing if the buffer
196	    // longer than 16.
197	    buffer_effective: [16]Span,
198	    // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
199	    // value (255), we will reset the effective buffer and this value.
200	    buffer_length: u8 = 0,
201	    // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
202	    // calculate backspaces and replacement characters.
203	    buffer_modification_index: i8 = -1,
204	    // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
205	    // switch, input cancellation, exceed effective buffer). This value is independent from mode and
206	    // has higher priority, e.g. if the mode is `telex` but the engine is working on position on or
207	    // after literal index, the engine will skip Vietnamese input processing (we only count positive
208	    // value, -1 mean no literal index).
209	    literal_index: i8 = -1,
210	    // Determine if we will process input in the specified mode (Telex) or append the character as is.
211	    mode: InputMode = .literal,
212	
213	    // Initialize the State on allocated memory.
214	    pub fn init(self: *State) void {
215	        self.* = .{
216	            .buffer_effective = undefined,
217	        };
218	    }
219	
220	    pub fn add(self: *State, c: u8) void {
221	        // Only allow a-zA-Z.
222	        assert(std.ascii.isAlphabetic(c));
223	
224	        // The buffer_modification index must be inbound of the buffer_effective.
225	        assert(self.buffer_modification_index >= -1 and self.buffer_modification_index < self.buffer_effective.len);
226	
227	        // The literal_index value must be in range -1 -> 16 (buffer_effective length) because we won't
228	        // process Vietnamese input outside the buffer_effective.
229	        assert(self.literal_index >= -1 and self.literal_index <= self.buffer_effective.len);
230	        // The literal_index value must be less than buffer length.
231	        assert(self.literal_index < self.buffer_length);
232	
233	        // Input mode must be either .literal or .telex.
234	        assert(self.mode == .literal or self.mode == .telex);
235	
236	        switch (c) {
237	            'A', 'a' => { // circumflex.
238	                if (self.literal_index > -1 or self.mode == .literal) {
239	                    // Enable literal input when literal_index is set or on literal mode. The
240	                    // literal_index is also set when the word starts with non-Vietnamese onsets.
241	
242	                    // Check if we can add new span for input character.
243	                    if (self.buffer_length < self.buffer_effective.len) {
244	                        // Add character to span.
245	                        self.buffer_effective[self.buffer_length] = Span.init(c);
246	                    }
247	                    // Increase the buffer length for tracking, we will need it went handling backspace.
248	                    self.buffer_length = self.buffer_length + 1;
249	
250	                    // Set modification index to -1 because we didn't modify any existing span.
251	                    self.buffer_modification_index = -1;
252	                } else {
253	                    // buffer_length must inbound of buffer_effective.
254	                    assert(self.buffer_length < self.buffer_effective.len);
255	
256	                    // literal_index must not be set in order to process Vietnamese input.
257	                    assert(self.literal_index == -1);
258	
259	                    // Vietnamese input.
260	                    // Possible cases:

261	                    // - circumplex.
262	                    // - cancel circumflex.
263	                    // - plain append.
264	
265	                    if (self.buffer_length == 0 or (self.buffer_effective[self.buffer_length - 1].base != std.ascii.toUpper(c) and self.buffer_effective[self.buffer_length - 1].base != std.ascii.toLower(c))) {
266	                        // Plain append when start of the buffer or the previous character don't match
267	                        // circumflex rules.
268	
269	                        // Check if we can add new span for input character.
270	                        if (self.buffer_length < self.buffer_effective.len) {
271	                            // Add character to span.
272	                            self.buffer_effective[self.buffer_length] = Span.init(c);
273	                        }
274	                        // Increase the buffer length for tracking, we will need it went handling
275	                        // backspace.
276	                        self.buffer_length = self.buffer_length + 1;
277	
278	                        // Set modification index to -1 because we didn't modify any existing span.
279	                        self.buffer_modification_index = -1;
280	                    } else if ((self.buffer_effective[self.buffer_length - 1].base == std.ascii.toUpper(c) or self.buffer_effective[self.buffer_length - 1].base == std.ascii.toLower(c)) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
281	                        // Circumflex.
282	
283	                        // Add circumflex to previous plan 'A' or 'a'.
284	                        self.buffer_effective[self.buffer_length - 1].diacritic = .circumflex;
285	                        // Mark modification index.
286	                        self.buffer_modification_index = @intCast(self.buffer_length - 1);
287	                    } else if ((self.buffer_effective[self.buffer_length - 1].base == std.ascii.toUpper(c) or self.buffer_effective[self.buffer_length - 1].base == std.ascii.toLower(c)) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
288	                        // Cancel circumflex.
289	
290	                        // Reset diacritic to empty.
291	                        self.buffer_effective[self.buffer_length - 1].diacritic = .empty;
292	                        // Mark modification index.
293	                        self.buffer_modification_index = @intCast(self.buffer_length - 1);
294	
295	                        // Add plan character to buffer_effective.
296	                        // Check if we can add new span for input character.
297	                        if (self.buffer_length < self.buffer_effective.len) {
298	                            // Add character to span.
299	                            self.buffer_effective[self.buffer_length] = Span.init(c);
300	                        }
301	                        // Mark the start of literal input because of the cancelling.
302	                        self.literal_index = @intCast(self.buffer_length);
303	
304	                        // Increase the buffer length for tracking, we will need it went handling
305	                        // backspace.
306	                        self.buffer_length = self.buffer_length + 1;
307	                    } else {
308	                        unreachable;
309	                    }
310	                }
311	            },
312	            'C', 'c' => {}, // fill missing diacritic, e.g. cước.
313	            'D', 'd' => {}, // bar.
314	            'E', 'e' => {}, // circumflex.
315	            'F', 'f' => {}, // falling.
316	            'I', 'i' => {}, // fill missing diacritic, e.g. người.
317	            'J', 'j' => {}, // falling_glottalized.
318	            'M', 'm' => {}, // fill missing diacritic, e.g. cườm.
319	            'N', 'n' => {}, // fill missing diacritic, e.g. cường.
320	            'O', 'o' => {}, // circumflex.
321	            'P', 'p' => {}, // fill missing diacritic, e.g. cướp.
322	            'R', 'r' => {}, // dipping_rising.
323	            'S', 's' => {}, // rising.
324	            'T', 't' => {}, // fill missing diacritic, e.g. trượt.
325	            'U', 'u' => {}, // fill missing diacritic, e.g. hươu.
326	            'W', 'w' => {}, // breve.
327	            'X', 'x' => {}, // rising_glottalized.
328	            'Z', 'z' => {}, // level / reset.
329	            else => { // literal.
330	                // These characters will be added to state literally.
331	
332	                // Check if we can add new span for input character.
333	                if (self.buffer_length < self.buffer_effective.len) {
334	                    // Add character to span.
335	                    self.buffer_effective[self.buffer_length] = Span.init(c);
336	                }
337	                // Increase the buffer length for tracking, we will need it went handling backspace.
338	                self.buffer_length = self.buffer_length + 1;
339	
340	                // Set modification index to -1 because we didn't modify any existing span.
341	                self.buffer_modification_index = -1;
342	                // Set literal index if it's not set and the length exceed the buffer_effective.
343	                if (self.literal_index == -1 and self.buffer_length > self.buffer_effective.len) {
344	                    // Set literal mode since buffer index 16 (just after the last buffer_effective
345	                    // item) because we don't have span for these position, we stop processing Telex
346	                    // rules but we will continue processing if user use backspaces to move back to the
347	                    // buffer_effective range, all existing spans must work as expected.
348	                    self.literal_index = self.buffer_effective.len;
349	                }
350	            },
351	        }
352	    }
353	
354	    pub fn backspace(self: *State) void {
355	        // buffer_length must be positive for backspace.
356	        assert(self.buffer_length > 0);
357	    }
358	};
