360	// Simple ABI wrapper for initialize allocated memory.
361	export fn lex_state_init(state: *State) void {
362	    state.init();
363	}
364	
365	// Needed for the caller to allocate memory for our State.
366	export const lex_state_size: usize = @sizeOf(State);
367	
368	// Needed for the caller to allocate memory for our State.
369	export const lex_state_alignment: usize = @alignOf(State);
370	
371	// Add operations to the given state based on Telex rules, operations are determined by the input
372	// character.
373	export fn lex_add(state: *State, c: u8) void {
374	    state.add(c);
375	}
