377	test "expect lex_add handles non-Telex characters less than buffer_effective range" {
378	    // Arrange
379	
380	    // Allocate memory, only specify on this test to simulate runtime allocation.
381	    const raw_pointer = std.testing.allocator.rawAlloc(lex_state_size, .fromByteUnits(lex_state_alignment), @returnAddress()) orelse return error.OutOfMemory;
382	    defer std.testing.allocator.rawFree(raw_pointer[0..lex_state_size], .fromByteUnits(lex_state_alignment), @returnAddress());
383	    const state: *align(lex_state_alignment) State = @ptrCast(@alignCast(raw_pointer));
384	
385	    // Initialize state.
386	    lex_state_init(state);
387	    state.mode = .telex;
388	
389	    const input_sequence = "bbbbbqqqqq";
390	
391	    // Act
392	    for (input_sequence) |c| {
393	        lex_add(state, c);
394	    }
395	
396	    // Assert
397	    // We only fill and increase the buffer_length based on input.
398	    try expectEqual(10, state.buffer_length);
399	    // Because we don't modify any existing character since the last input, expect -1.
400	    try expectEqual(-1, state.buffer_modification_index);
401	    // Because we didn't exceed the buffer_affective, don't set literal_index.
402	    try expectEqual(-1, state.literal_index);
403	    // Don't touch on input mode.
404	    try expectEqual(.telex, state.mode);
405	    // Verify every the spans, must exactly the same with the input.
406	    for (input_sequence, 0..) |c, i| {
407	        const sp = state.buffer_effective[i];
408	        try expectEqual(c, sp.base);
409	        try expectEqual(.empty, sp.diacritic);
410	        try expectEqual(.level, sp.tone);
411	    }
412	}
