12: pub const RepairBudgetJournal = struct {
13:     capacity: u32,
14:     available: u32,
15: 
16:     replica_index: u8,
17: 
18:     // Tracks the prepare ops requested from each remote replica.
19:     replicas_requested_prepares: []RequestedPrepares,
20: 
21:     // Exponential weighted moving average of the repair latency for each remote replica.
22:     //
23:     // Repair latency is calculated as the duration elapsed between when a prepare is requested from
24:     // a remote replica, and when it is either received from the remote replica (see `decrement`),
25:     // or expired (see `reap_expired_requests`).
26:     replicas_repair_latency: []stdx.Duration,
27: 
28:     // Probability of choosing a random replica with available budget, as opposed to one with the
29:     // best repair latency with available budget.
30:     //
31:     // Experiments ensure that we try alternative repair routes, and avoids potential resonance
32:     // wherein we keep requesting from a permanently crashed replica with the best repair latency.
33:     // This is because we don't penalize the repair latency once it exceeds `duration_expiry_max`,
34:     // so if a crashed replica has the best latency, it may remain that way forever.
35:     experiment_chance: Ratio = ratio(1, 10),
36: 
37:     // Multiple of repair latency used to determine expiry duration, which is the time we wait
38:     // before restoring the budget for an inflight repair request if the prepare has not arrived.
39:     repair_latency_multiple_expiry: u8 = 2,
40: 
41:     // The maximum amount of time we wait before reclaiming the budget for an inflight repair
42:     // request if the prepare has not arrived.
43:     //
44:     // Capped at 500ms to avoid an unbounded increase in the tracked repair latency for remote
45:     // replicas. Specifically, helps avoid the case where a partitioned replica with missing
46:     // prepares gets into a cycle of requesting prepares, waiting for them to expire, and then
47:     // increasing the repair latency on expiry.
48:     duration_expiry_max: stdx.Duration = .ms(500),
49: 
50:     // Maximum inflight `request_prepare` messages per remote replica, at any point of time.
51:     //
52:     // This is kept small to ensure that even if the budget to a remote replica is saturated
53:     // by multiple replicas, overflowing the egress `send_queue` (which leads to dropped messages)
54:     // on the remote replica is unlikely. For example, since the `send_queue` is currently sized
55:     // to 4 messages, if we were to set this limit to 4 as well, multiple repairing replicas are
56:     // more likely to overflow the remote replica's send queue.
57:     const repair_messages_inflight_count_max = 2;
58: 
59:     const RequestedPrepares = std.AutoArrayHashMapUnmanaged(u64, stdx.Instant);
60: 
61:     pub fn init(gpa: std.mem.Allocator, options: struct {
62:         replica_index: u8,
63:         replica_count: u8,
64:     }) !RepairBudgetJournal {
65:         // Replicas can repair from all replicas but themselves,
66:         // while standbys can repair from all replicas.
67:         const remote_replica_count =
68:             options.replica_count - @intFromBool(options.replica_index < options.replica_count);
69: 
70:         var replicas_requested_prepares = try gpa.alloc(RequestedPrepares, options.replica_count);
71:         errdefer gpa.free(replicas_requested_prepares);
72: 
73:         for (replicas_requested_prepares, 0..) |*requested_prepares, replica| {
74:             errdefer for (replicas_requested_prepares[0..replica]) |*m| m.deinit(gpa);
75:             requested_prepares.* = .{};
76: 
77:             try requested_prepares.ensureTotalCapacity(gpa, repair_messages_inflight_count_max);
78:             errdefer requested_prepares.deinit(gpa);
79:         }
80: 
81:         errdefer for (replicas_requested_prepares) |*m| m.deinit(gpa);
82: 
83:         const replicas_repair_latency = try gpa.alloc(stdx.Duration, options.replica_count);
84:         errdefer gpa.free(replicas_repair_latency);
85: 
86:         // Initialize repair latency to 1 ms for all replicas, this gets refined as we start
87:         // repairing from these replicas. We choose a value lower than the the typical latency
88:         // between two replicas, so as to not bias replica selection when we have few measurements.
89:         @memset(replicas_repair_latency, .ms(1));
90: 
91:         return RepairBudgetJournal{
92:             .capacity = repair_messages_inflight_count_max * remote_replica_count,
93:             .available = repair_messages_inflight_count_max * remote_replica_count,
94:             .replica_index = options.replica_index,
95:             .replicas_requested_prepares = replicas_requested_prepares,
96:             .replicas_repair_latency = replicas_repair_latency,
97:         };
98:     }
99: 
100:     pub fn deinit(budget: *RepairBudgetJournal, gpa: std.mem.Allocator) void {
101:         for (budget.replicas_requested_prepares) |*requested_prepares| {
102:             requested_prepares.deinit(gpa);
103:         }
104:         gpa.free(budget.replicas_requested_prepares);
105:         gpa.free(budget.replicas_repair_latency);
106:     }
107: 
108:     /// Returns the index of the replica with the lowest repair latency, and budget availability, if
109:     /// one exists. Otherwise, returns null. For a fraction of ops (guided by `experiment_chance`),
110:     /// diverges from this heuristic and returns the index of a random replica with budget
111:     /// availability, using reservoir sampling.
112:     pub fn decrement(
113:         budget: *RepairBudgetJournal,
114:         op: u64,
115:         now: stdx.Instant,
116:         prng: *stdx.PRNG,
117:     ) ?u8 {
118:         assert(budget.capacity > 0);
119:         maybe(budget.available == 0);
120: 
121:         budget.assert_invariants();
122:         defer budget.assert_invariants();
123: 
124:         const experiment = prng.chance(budget.experiment_chance);
125:         var experiment_replica_index: ?u8 = null;
126:         var reservoir = stdx.PRNG.Reservoir.init();
127: 
128:         var repair_latency_min: ?stdx.Duration = null;
129:         var repair_latency_min_replica_index: ?u8 = null;
130: 
131:         for (budget.replicas_requested_prepares, 0..) |*requested_prepares, replica_index| {
132:             // Disallow requests to self.
133:             if (replica_index == budget.replica_index) continue;
134:             // Enforce per-replica budget.
135:             if (requested_prepares.count() == repair_messages_inflight_count_max) continue;
136:             // Disallow requesting from a replica from which this op has already been requested.
137:             if (requested_prepares.get(op) != null) continue;
138: 
139:             const replica_repair_latency = budget.replicas_repair_latency[replica_index];
140: 
141:             if (repair_latency_min == null or replica_repair_latency.ns < repair_latency_min.?.ns) {
142:                 repair_latency_min = replica_repair_latency;
143:                 repair_latency_min_replica_index = @intCast(replica_index);
144:             }
145: 
146:             // Reservoir sampling with an arbitrarily chosen weight of 1 for each item suffices
147:             // our use case, as the goal is to get some degree of randomness during experiments.
148:             if (reservoir.replace(prng, 1)) {
149:                 experiment_replica_index = @intCast(replica_index);
150:             }
151:         }
152:         assert((repair_latency_min == null) == (repair_latency_min_replica_index == null));
153:         assert((repair_latency_min_replica_index == null) == (experiment_replica_index == null));
154: 
155:         const replica_index_maybe = if (experiment)
156:             experiment_replica_index
157:         else
158:             repair_latency_min_replica_index;
159: 
160:         if (replica_index_maybe) |replica_index| {
161:             assert(replica_index != budget.replica_index);
162:             budget.replicas_requested_prepares[replica_index].putAssumeCapacityNoClobber(op, now);
163:             budget.available -= 1;
164:         }
165: 
166:         return replica_index_maybe;
167:     }
168: 
169:     /// Increments the budget by 1 for each replica that this prepare op has been requested from.
170:     /// Also refines the repair latency for each of these replicas.
171:     pub fn increment(budget: *RepairBudgetJournal, op: u64, now: stdx.Instant) void {
172:         budget.assert_invariants();
173:         defer budget.assert_invariants();
174: 
175:         for (budget.replicas_requested_prepares, 0..) |*requested_prepares, replica_index| {
176:             if (requested_prepares.fetchSwapRemove(op)) |requested_prepare| {
177:                 budget.available += 1;
178: 
179:                 // We have no information about the replica that sent this prepare, as the message
180:                 // header stores the index of the primary processed that prepare. Consequently, we
181:                 // refine repair latency for all replicas that this prepare op was requested from.
182:                 // This would lead to some inaccuracy in the latency measurement, but is acceptable
183:                 // since the scenario where a prepare has been requested from multiple replicas is
184:                 // rare in practice. The more common scenario is that we have a large number of
185:                 // prepares missing (for e.g. after state sync, or if a lagging replica transitions
186:                 // to a new checkpoint), in which case we request a unique op from each replica.
187:                 budget.replicas_repair_latency[replica_index] = ewma_add_duration(
188:                     budget.replicas_repair_latency[replica_index],
189:                     now.duration_since(requested_prepare.value),
190:                 );
191:             }
192:         }
193:     }
194: 
195:     pub fn refill(budget: *RepairBudgetJournal) void {
196:         budget.assert_invariants();
197:         defer budget.assert_invariants();
198: 
199:         for (budget.replicas_requested_prepares) |*requested_prepares| {
200:             requested_prepares.clearRetainingCapacity();
201:         }
202:         budget.available = budget.capacity;
203:     }
204: 
205:     /// Iterates through the inflight requests across all remote replicas, and reclaims the budget
206:     /// for expired requests. Penalizes the replicas for which some expired requests were found,
207:     /// duration spent waiting for the expired requests to their repair latency.
208:     ///
209:     /// Expiry provides resilience to network faults, by ensuring that a dropped packet or the
210:     /// remote replica crashing doesn't cause an op to get stuck in the queue for a remote replica.
211:     /// We avoid spurious expiry due to transient network hiccups like increased latency by waiting
212:     /// for twice the measured repair latency.
213:     pub fn reap_expired_requests(budget: *RepairBudgetJournal, now: stdx.Instant) void {
214:         budget.assert_invariants();
215:         defer budget.assert_invariants();
216: 
217:         for (budget.replicas_requested_prepares, 0..) |*requested_prepares, replica_index| {
218:             var requested_prepares_index: u32 = 0;
219: 
220:             while (requested_prepares_index < requested_prepares.entries.len) {
221:                 const requested_at = requested_prepares.values()[requested_prepares_index];
222:                 const duration_since_requested_at = now.duration_since(requested_at);
223:                 const duration_expiry_ns = @min(
224:                     budget.repair_latency_multiple_expiry *
225:                         budget.replicas_repair_latency[replica_index].ns,
226:                     budget.duration_expiry_max.ns,
227:                 );
228:                 if (duration_since_requested_at.ns > duration_expiry_ns) {
229:                     requested_prepares.swapRemoveAt(requested_prepares_index);
230:                     budget.replicas_repair_latency[replica_index] = ewma_add_duration(
231:                         budget.replicas_repair_latency[replica_index],
232:                         duration_since_requested_at,
233:                     );
234:                     budget.available += 1;
235:                 } else {
236:                     requested_prepares_index += 1;
237:                 }
238:             }
239:         }
240:     }
241: 
242:     fn assert_invariants(budget: *const RepairBudgetJournal) void {
243:         assert(budget.available <= budget.capacity);
244:         if (budget.replica_index < budget.replicas_requested_prepares.len) {
245:             assert(budget.replicas_requested_prepares[budget.replica_index].count() == 0);
246:         }
247: 
248:         var requested_prepares_count: u32 = 0;
249:         for (budget.replicas_requested_prepares) |*requested_prepares| {
250:             requested_prepares_count += @intCast(requested_prepares.count());
251:         }
252:         assert(budget.capacity - budget.available == requested_prepares_count);
253:     }
254: 
255:     fn ewma_add_duration(old: stdx.Duration, new: stdx.Duration) stdx.Duration {
256:         return .{
257:             .ns = @divFloor((old.ns * 4) + new.ns, 5),
258:         };
259:     }
260: };
