262: pub const RepairBudgetGrid = struct {
263:     capacity: u32,
264:     available: u32,
265:     replica_index: u8,
266: 
267:     // Tracks the blocks requested from each remote replica.
268:     replicas_requested_blocks: []RequestedBlocks,
269: 
270:     // The amount of time we wait before restoring the budget for an
271:     // inflight repair request if the block has not arrived.
272:     const duration_expiry: stdx.Duration = .ms(250);
273: 
274:     // The amount of time we wait before re-requesting a block
275:     // which has not yet arrived.
276:     const duration_retry: stdx.Duration = .ms(100);
277: 
278:     // Maximum blocks that can be requested per remote replica.
279:     //
280:     // We use a small number to ensure that even if the budget to a
281:     // remote replica is saturated by multiple replicas, overflowing
282:     // the egress `send_queue` (which leads to dropped messages, and
283:     // wasted network & storage IO) on the remote replica is unlikely.
284:     // The +1 allows us to send a full `request_blocks` even when
285:     // all but one request has been responded to.
286:     const replica_blocks_requested_max = constants.grid_repair_request_max + 1;
287: 
288:     const RequestedBlocks = std.AutoArrayHashMapUnmanaged(vsr.BlockReference, stdx.Instant);
289: 
290:     pub fn init(gpa: std.mem.Allocator, options: struct {
291:         replica_index: u8,
292:         replica_count: u8,
293:     }) !RepairBudgetGrid {
294:         // Replicas can repair from all replicas but themselves,
295:         // while standbys can repair from all replicas.
296:         const remote_replica_count =
297:             options.replica_count - @intFromBool(options.replica_index < options.replica_count);
298: 
299:         var replicas_requested_blocks = try gpa.alloc(RequestedBlocks, options.replica_count);
300:         errdefer gpa.free(replicas_requested_blocks);
301: 
302:         for (replicas_requested_blocks, 0..) |*requested_blocks, replica| {
303:             errdefer for (replicas_requested_blocks[0..replica]) |*m| m.deinit(gpa);
304:             requested_blocks.* = .{};
305: 
306:             try requested_blocks.ensureTotalCapacity(gpa, replica_blocks_requested_max);
307:             errdefer requested_blocks.deinit(gpa);
308:         }
309:         errdefer for (replicas_requested_blocks) |*m| m.deinit(gpa);
310: 
311:         return RepairBudgetGrid{
312:             .capacity = replica_blocks_requested_max * remote_replica_count,
313:             .available = replica_blocks_requested_max * remote_replica_count,
314:             .replica_index = options.replica_index,
315:             .replicas_requested_blocks = replicas_requested_blocks,
316:         };
317:     }
318: 
319:     pub fn deinit(budget: *RepairBudgetGrid, gpa: std.mem.Allocator) void {
320:         for (budget.replicas_requested_blocks) |*requested_blocks| {
321:             requested_blocks.deinit(gpa);
322:         }
323:         gpa.free(budget.replicas_requested_blocks);
324:     }
325: 
326:     fn assert_invariants(budget: *const RepairBudgetGrid) void {
327:         assert(budget.available <= budget.capacity);
328: 
329:         if (budget.replica_index < budget.replicas_requested_blocks.len) {
330:             assert(budget.replicas_requested_blocks[budget.replica_index].count() == 0);
331:         }
332: 
333:         var requested_blocks_count: u32 = 0;
334:         for (budget.replicas_requested_blocks) |*requested_blocks| {
335:             requested_blocks_count += @intCast(requested_blocks.count());
336:         }
337: 
338:         assert(budget.available + requested_blocks_count == budget.capacity);
339:     }
340: 
341:     pub fn next_destination(budget: *RepairBudgetGrid, prng: *stdx.PRNG) ?u8 {
342:         budget.assert_invariants();
343:         defer budget.assert_invariants();
344: 
345:         const replica_count = budget.replicas_requested_blocks.len;
346:         var replica_indexes: [constants.replicas_max]u8 = undefined;
347:         for (replica_indexes[0..replica_count], 0..) |*replica, i| replica.* = @intCast(i);
348:         prng.shuffle(u8, replica_indexes[0..replica_count]);
349: 
350:         for (replica_indexes[0..replica_count]) |replica_index| {
351:             if (replica_index != budget.replica_index and
352:                 budget.budget_available(replica_index) >= constants.grid_repair_request_max)
353:             {
354:                 return replica_index;
355:             }
356:         }
357:         return null;
358:     }
359: 
360:     pub fn budget_available(budget: *const RepairBudgetGrid, replica_index: u8) u32 {
361:         budget.assert_invariants();
362: 
363:         assert(budget.replica_index != replica_index);
364: 
365:         const replica_requested_blocks = budget.replicas_requested_blocks[replica_index];
366: 
367:         return @intCast(replica_blocks_requested_max - replica_requested_blocks.count());
368:     }
369: 
370:     pub fn decrement(
371:         budget: *RepairBudgetGrid,
372:         block_identifier: vsr.BlockReference,
373:         replica_index: u8,
374:         now: stdx.Instant,
375:     ) bool {
376:         budget.assert_invariants();
377:         defer budget.assert_invariants();
378: 
379:         assert(budget.available > 0);
380:         assert(block_identifier.address > 0);
381:         assert(replica_index != budget.replica_index);
382: 
383:         var duration_since_requested_min: ?stdx.Duration = null;
384: 
385:         for (budget.replicas_requested_blocks, 0..) |requested_blocks, index| {
386:             if (requested_blocks.get(block_identifier)) |requested_at| {
387:                 assert(index != budget.replica_index);
388:                 const duration_since_requested = now.duration_since(requested_at);
389:                 if (duration_since_requested_min == null or
390:                     duration_since_requested.ns < duration_since_requested_min.?.ns)
391:                 {
392:                     duration_since_requested_min = duration_since_requested;
393:                 }
394:             }
395:         }
396: 
397:         if (duration_since_requested_min) |duration| {
398:             if (duration.ns < duration_retry.ns) return false;
399:         }
400: 
401:         var replica_requested_blocks =
402:             &budget.replicas_requested_blocks[replica_index];
403: 
404:         assert(replica_requested_blocks.count() < replica_blocks_requested_max);
405: 
406:         const gop = replica_requested_blocks.getOrPutAssumeCapacity(block_identifier);
407:         gop.value_ptr.* = now;
408: 
409:         if (!gop.found_existing) budget.available -= 1;
410: 
411:         return true;
412:     }
413: 
414:     pub fn increment(budget: *RepairBudgetGrid, block_identifier: vsr.BlockReference) void {
415:         budget.assert_invariants();
416:         defer budget.assert_invariants();
417: 
418:         // We have no information about the replica that sent
419:         // this block, as storing each replica's index in the
420:         // block header would make storage non-deterministic.
421:         // Consequently, we increase the budget for all replicas
422:         // this block was requested from. This is safe to do as
423:         // we only invoke `increment` *once* -- when the replica
424:         // either uses the block to serve a read that's waiting
425:         // on this block, or a repair write (see `on_block`).
426:         for (budget.replicas_requested_blocks) |*requested_blocks| {
427:             if (requested_blocks.swapRemove(block_identifier)) {
428:                 budget.available += 1;
429:             }
430:         }
431:     }
432: 
433:     pub fn refill(budget: *RepairBudgetGrid) void {
434:         budget.assert_invariants();
435:         defer budget.assert_invariants();
436: 
437:         budget.available = budget.capacity;
438: 
439:         for (budget.replicas_requested_blocks) |*replicas_requested_blocks| {
440:             replicas_requested_blocks.clearRetainingCapacity();
441:         }
442:     }
443: 
444:     pub fn reap_expired_requests(budget: *RepairBudgetGrid, now: stdx.Instant) void {
445:         budget.assert_invariants();
446:         defer budget.assert_invariants();
447: 
448:         for (budget.replicas_requested_blocks) |*requested_blocks| {
449:             var requested_blocks_index: u32 = 0;
