509: pub inline fn hash_inline(value: anytype) u64 {
510:     comptime {
511:         assert(no_padding(@TypeOf(value)));
512:         assert(has_unique_representation(@TypeOf(value)));
513:     }
514:     return low_level_hash(0, switch (@typeInfo(@TypeOf(value))) {
515:         .@"struct", .int => std.mem.asBytes(&value),
516:         else => @compileError("unsupported hashing for " ++ @typeName(@TypeOf(value))),
