520: /// Inline version of Google Abseil "LowLevelHash" (inspired by wyhash).
521: /// https://github.com/abseil/abseil-cpp/blob/master/absl/hash/internal/low_level_hash.cc
522: inline fn low_level_hash(seed: u64, input: anytype) u64 {
523:     const salt = [_]u64{
524:         0xa0761d6478bd642f,
525:         0xe7037ed1a0b428db,
526:         0x8ebc6af09c88c6e3,
527:         0x589965cc75374cc3,
528:         0x1d8e4e27c47d124f,
529:     };
530: 
531:     var in: []const u8 = input;
532:     var state = seed ^ salt[0];
533:     const starting_len = input.len;
534: 
535:     if (in.len > 64) {
536:         var dup = [_]u64{ state, state };
537:         defer state = dup[0] ^ dup[1];
538: 
539:         while (in.len > 64) : (in = in[64..]) {
540:             for (@as([2][4]u64, @bitCast(in[0..64].*)), 0..) |chunk, i| {
541:                 const mix1 = @as(u128, chunk[0] ^ salt[(i * 2) + 1]) *% (chunk[1] ^ dup[i]);
542:                 const mix2 = @as(u128, chunk[2] ^ salt[(i * 2) + 2]) *% (chunk[3] ^ dup[i]);
543:                 dup[i] = @as(u64, @truncate(mix1 ^ (mix1 >> 64)));
544:                 dup[i] ^= @as(u64, @truncate(mix2 ^ (mix2 >> 64)));
545:             }
546:         }
547:     }
548: 
549:     while (in.len > 16) : (in = in[16..]) {
550:         const chunk = @as([2]u64, @bitCast(in[0..16].*));
551:         const mixed = @as(u128, chunk[0] ^ salt[1]) *% (chunk[1] ^ state);
552:         state = @as(u64, @truncate(mixed ^ (mixed >> 64)));
553:     }
554: 
555:     var chunk: [2]u64 = .{ 0, 0 };
556:     if (in.len > 8) {
557:         chunk[0] = @as(u64, @bitCast(in[0..8].*));
558:         chunk[1] = @as(u64, @bitCast(in[in.len - 8 ..][0..8].*));
559:     } else if (in.len > 3) {
560:         chunk[0] = @as(u32, @bitCast(in[0..4].*));
561:         chunk[1] = @as(u32, @bitCast(in[in.len - 4 ..][0..4].*));
562:     } else if (in.len > 0) {
563:         chunk[0] = (@as(u64, in[0]) << 16) | (@as(u64, in[in.len / 2]) << 8) | in[in.len - 1];
564:     }
565: 
566:     var mixed = @as(u128, chunk[0] ^ salt[1]) *% (chunk[1] ^ state);
567:     mixed = @as(u64, @truncate(mixed ^ (mixed >> 64)));
568:     mixed *%= (@as(u64, starting_len) ^ salt[1]);
569:     return @as(u64, @truncate(mixed ^ (mixed >> 64)));
570: }
