600: // std.SemanticVersion requires there be no extra characters after the
601: // major/minor/patch numbers. But when we try to parse `uname
602: // --kernel-release` (note: while Linux doesn't follow semantic
603: // versioning, it doesn't violate it either), some distributions have
604: // extra characters, such as this Fedora one: 6.3.8-100.fc37.x86_64, and
605: // this WSL one has more than three dots:
606: // 5.15.90.1-microsoft-standard-WSL2.
607: pub fn parse_dirty_semver(dirty_release: []const u8) !std.SemanticVersion {
608:     const release = blk: {
609:         var last_valid_version_character_index: usize = 0;
610:         var dots_found: u8 = 0;
611:         for (dirty_release) |c| {
612:             if (c == '.') dots_found += 1;
613:             if (dots_found == 3) {
614:                 break;
615:             }
616: 
617:             if (c == '.' or (c >= '0' and c <= '9')) {
618:                 last_valid_version_character_index += 1;
619:                 continue;
620:             }
621: 
622:             break;
623:         }
624: 
625:         break :blk dirty_release[0..last_valid_version_character_index];
626:     };
627: 
628:     return std.SemanticVersion.parse(release);
629: }
