1479:         /// Time is measured in logical ticks that are incremented on every call to tick().
1480:         /// This eliminates a dependency on the system time and enables deterministic testing.
1481:         pub fn tick(self: *Replica) void {
1482:             self.trace.start(.loop_tick);
1483:             defer self.trace.stop(.loop_tick);
1484: 
1485:             assert(self.opened);
1486:             // Ensure that all asynchronous IO callbacks flushed the loopback queue as needed.
1487:             // If an IO callback queues a loopback message without flushing the queue then this will
1488:             // delay the delivery of messages (e.g. a prepare_ok from the primary to itself) and
1489:             // decrease throughput significantly.
1490:             assert(self.loopback_queue == null);
1491:             defer self.invariants();
1492: 
1493:             if (self.message_bus.resume_needed()) {
1494:                 // See fn suspend_message conditions.
1495:                 assert(self.journal.writes.available() == 0 or
1496:                     self.grid_repair_writes.available() == 0 or
1497:                     self.syncing == .updating_checkpoint);
1498:             }
1499: 
1500:             if (self.status == .normal and !self.standby()) {
1501:                 self.tick_normal_heartbeat_fault();
1502:             }
1503: 
1504:             self.clock.tick();
1505:             self.message_bus.tick();
1506:             self.multiversion.tick();
1507: 
1508:             const timeouts = .{
1509:                 .{ &self.ping_timeout, on_ping_timeout },
1510:                 .{ &self.prepare_timeout, on_prepare_timeout },
1511:                 .{ &self.primary_abdicate_timeout, on_primary_abdicate_timeout },
1512:                 .{ &self.commit_message_timeout, on_commit_message_timeout },
1513:                 .{ &self.exit_view_window_timeout, on_exit_view_window_timeout },
1514:                 .{ &self.exit_view_message_timeout, on_exit_view_message_timeout },
1515:                 .{ &self.view_change_status_timeout, on_view_change_status_timeout },
1516:                 .{ &self.join_view_message_timeout, on_join_view_message_timeout },
1517:                 .{
1518:                     &self.request_view_message_timeout,
1519:                     on_request_view_message_timeout,
1520:                 },
1521:                 .{ &self.journal_repair_timeout, on_journal_repair_timeout },
1522: 
1523:                 .{ &self.repair_sync_timeout, on_repair_sync_timeout },
1524:                 .{ &self.grid_repair_timeout, on_grid_repair_timeout },
1525:                 .{ &self.upgrade_timeout, on_upgrade_timeout },
1526:                 .{ &self.pulse_timeout, on_pulse_timeout },
1527:                 .{ &self.grid_scrub_timeout, on_grid_scrub_timeout },
1528:                 .{ &self.trace_emit_timeout, on_trace_emit_timeout },
1529:                 .{ &self.commit_stall_timeout, on_commit_stall_timeout },
1530:             };
1531: 
1532:             inline for (timeouts) |timeout| {
1533:                 timeout[0].tick();
1534:             }
1535:             inline for (timeouts) |timeout| {
1536:                 if (timeout[0].fired()) timeout[1](self);
1537:             }
1538: 
1539:             // None of the on_timeout() functions above should send a message to this replica.
1540:             assert(self.loopback_queue == null);
1541:         }
