1543:         fn tick_normal_heartbeat_fault(self: *Replica) void {
1544:             assert(self.status == .normal);
1545:             assert(self.backup() or self.primary());
1546:             assert(self.commit_fault.interval_min.to_ms() > 2 * constants.tick_ms);
1547:             assert(self.commit_fault.interval_ewma.to_ms() > 2 * constants.tick_ms);
1548: 
1549:             const now = self.clock.monotonic();
1550:             const tardy = self.commit_fault.tardy(now);
1551:             if (tardy == .green) return; // Everything is fine!
1552: 
1553:             if (self.primary()) {
1554:                 if (tardy == .red) {
1555:                     // Can only happen if there's an abnormal delay between ticks.
1556:                     log.warn(
1557:                         "{}: tick_normal_heartbeat_fault: tick delayed (interval={} delay={})",
1558:                         .{
1559:                             self.replica,
1560:                             self.commit_fault.interval_ewma,
1561:                             now.duration_since(self.commit_fault.signal_last),
1562:                         },
1563:                     );
1564:                 }
1565:                 // See FaultDetector smoothing test for why resetting the timeout is critical here.
1566:                 self.commit_message_timeout.reset();
1567:                 self.send_commit(now);
1568:             } else {
1569:                 assert(self.backup());
1570:                 if (tardy == .yellow) {
1571:                     // A slight delay which could be caused by a natural drop in the load,
1572:                     // so wait some more for a Commit message from the primary.
1573:                 } else {
1574:                     log.warn(
1575:                         "{}: tick_normal_heartbeat_fault: heartbeat lost (interval={} delay={})",
1576:                         .{
1577:                             self.replica,
1578:                             self.commit_fault.interval_ewma,
1579:                             now.duration_since(self.commit_fault.signal_last),
1580:                         },
1581:                     );
1582:                     self.send_exit_view();
1583:                     self.commit_fault.signal(now);
1584:                 }
1585:             }
1586:             assert(self.commit_fault.tardy(now) != .red);
1587:         }
