1595:         pub fn on_messages(self: *Replica, buffer: *MessageBuffer) void {
1596:             var message_count: u32 = 0;
1597:             var message_suspended_count: u32 = 0;
1598:             while (buffer.next_header()) |header| {
1599:                 message_count += 1;
1600:

1600: 
1601:                 if (header.cluster != self.cluster) {
1602:                     buffer.invalidate(.header_cluster);
1603:                     return;
1604:                 }
1605: 
1606:                 if (self.suspend_message(&header)) {
1607:                     buffer.suspend_message(&header);
1608:                     message_suspended_count += 1;
1609:                     continue;
1610:                 }
1611: 
1612:                 const message = buffer.consume_message(self.message_bus.pool, &header);
1613:                 defer self.message_bus.unref(message);
1614: 
1615:                 assert(message.references == 1);
1616: 
1617:                 // Avoid leaking sector padding for messages written to a block device:
1618:                 if (message.header.command == .request or
1619:                     message.header.command == .prepare or
1620:                     message.header.command == .block or
1621:                     message.header.command == .reply)
1622:                 {
1623:                     const sector_ceil = vsr.sector_ceil(message.header.size);
1624:                     if (message.header.size != sector_ceil) {
1625:                         assert(message.header.size < sector_ceil);
1626:                         assert(message.buffer.len == constants.message_size_max);
1627:                         @memset(message.buffer[message.header.size..sector_ceil], 0);
1628:                     }
1629:                 }
1630: 
1631:                 if (message.header.into(.request)) |request_header| {
1632:                     assert(request_header.client != 0 or self.aof_recovery);
1633:                 }
1634: 
1635:                 self.trace.count(.{ .replica_messages_in = .{
1636:                     .command = message.header.command,
1637:                 } }, 1);
1638:                 self.on_message(message);
1639:             }
1640: 
1641:             if (message_count > constants.bus_message_burst_warn_min) {
1642:                 log.warn("{}: on_messages: message count={} suspended={}", .{
1643:                     self.log_prefix(),
1644:                     message_count,
1645:                     message_suspended_count,
1646:                 });
1647:             }
1648:         }
