1653:                 .prepare => |header_prepare| if (self.journal.writes.available() == 0) {
1654:                     log.warn("{}: on_messages: suspending command=prepare " ++
1655:                         "op={} view={} checksum={x:0>32}", .{
1656:                         self.log_prefix(),
1657:                         header_prepare.op,
1658:                         header_prepare.view,
1659:                         header_prepare.checksum,
1660:                     });
