1681:         fn on_message(self: *Replica, message: *Message) void {
1682:             assert(self.opened);
1683:             assert(self.loopback_queue == null);
1684:             assert(message.references > 0);
1685:             defer self.invariants();
1686: 
1687:             log.debug("{}: on_message: view={} status={s} {}", .{
1688:                 self.log_prefix(),
1689:                 self.view,
1690:                 @tagName(self.status),
1691:                 message.header,
1692:             });
1693: 
1694:             if (constants.verify) {
1695:                 assert(message.header.valid_checksum_body(message.body_used()));
1696:             }
1697: 
1698:             if (message.header.invalid()) |reason| {
1699:                 log.warn("{}: on_message: invalid (command={}, {s})", .{
1700:                     self.log_prefix(),
1701:                     message.header.command,
1702:                     reason,
1703:                 });
1704:                 return;
1705:             }
1706: 
1707:             // No client or replica should ever send a .reserved message.
1708:             assert(message.header.command != .reserved);
1709: 
1710:             if (message.header.cluster != self.cluster) {
1711:                 log.warn("{}: on_message: wrong cluster (cluster must be {} not {})", .{
1712:                     self.log_prefix(),
1713:                     self.cluster,
1714:                     message.header.cluster,
1715:                 });
1716:                 return;
1717:             }
1718: 
1719:             switch (self.syncing) {
1720:                 .idle => {},
1721:                 .canceling_commit, .canceling_grid => {
1722:                     // Ignore further messages until finishing (asynchronous) processing
1723:                     // of sync View. This prevents our view number from jumping ahead of View.
1724:                     assert(self.sync_view != null);
1725:                     log.warn("{}: on_message: ignoring (syncing)", .{self.log_prefix()});
1726:                     return;
1727:                 },
1728:                 .updating_checkpoint => {},
1729:             }
1730: 
1731:             self.jump_view(message.header);
1732: 
1733:             assert(message.header.replica < self.node_count);
1734:             const message_any = message.into_any();
1735: 
1736:             // Don't rely on header.peer_type, since it's about who sent the message rather than
1737:             // who created it. Handle messages that have explicitly been created by a client.
1738:             switch (message_any) {
1739:                 inline .ping_client, .request => |m| {
1740:                     if (m.header.client != 0) {
1741:                         self.release_seen_client_min = @min(
1742:                             message.header.release.value,
1743:                             self.release_seen_client_min orelse message.header.release.value,
1744:                         );
1745:                         self.release_seen_client_max = @max(
1746:                             message.header.release.value,
1747:                             self.release_seen_client_max orelse message.header.release.value,
1748:                         );
1749:                     }
1750:                 },
1751:                 else => {},
1752:             }
1753: 
1754:             switch (message_any) {
1755:                 .ping => |m| self.on_ping(m),
1756:                 .pong => |m| self.on_pong(m),
1757:                 .ping_client => |m| self.on_ping_client(m),
1758:                 .request => |m| self.on_request(m),
1759:                 .prepare => |m| self.on_prepare(m),
1760:                 .prepare_ok => |m| self.on_prepare_ok(m),
1761:                 .reply => |m| self.on_reply(m),
1762:                 .commit => |m| self.on_commit(m),
1763:                 .exit_view => |m| self.on_exit_view(m),
1764:                 .join_view => |m| self.on_join_view(m),
1765:                 .view => |m| self.on_view(m),
1766:                 .request_view => |m| self.on_request_view(m),
1767:                 .request_prepare => |m| self.on_request_prepare(m),
1768:                 .request_headers => |m| self.on_request_headers(m),
1769:                 .request_reply => |m| self.on_request_reply(m),
1770:                 .headers => |m| self.on_headers(m),
1771:                 .request_blocks => |m| self.on_request_blocks(m),
1772:                 .block => |m| self.on_block(m),
1773:                 // A replica should never handle misdirected messages intended for a client:
1774:                 .pong_client, .eviction => {
1775:                     log.warn("{}: on_message: misdirected message ({s})", .{
1776:                         self.log_prefix(),
1777:                         @tagName(message.header.command),
1778:                     });
1779:                     return;
1780:                 },
1781:                 .reserved => unreachable,
1782:                 .deprecated_12 => unreachable,
1783:                 .deprecated_21 => unreachable,
1784:                 .deprecated_22 => unreachable,
1785:                 .deprecated_23 => unreachable,
1786:             }
1787: 
1788:             if (self.loopback_queue) |loopback_message| {
1789:                 log.err("{}: on_message: on_{s}() queued a {s} loopback message with no flush", .{
1790:                     self.log_prefix(),
1791:                     @tagName(message.header.command),
1792:                     @tagName(loopback_message.header.command),
1793:                 });
1794:                 // Any message handlers that loopback must take responsibility for the flush.
1795:                 @panic("loopback message with no flush");
1796:             }
1797:         }
