1801:         fn on_ping(self: *Replica, message: *const Message.Ping) void {
1802:             assert(message.header.command == .ping);
1803:             if (self.status != .normal and self.status != .view_change) return;
1804: 
1805:             assert(self.status == .normal or self.status == .view_change);
1806: 
1807:             if (message.header.replica == self.replica) {
1808:                 log.warn("{}: on_ping: misdirected message (self)", .{self.log_prefix()});
1809:                 return;
1810:             }
1811: 
1812:             // TODO Drop pings that were not addressed to us.
1813: 
1814:             self.send_header_to_replica(message.header.replica, @bitCast(Header.Pong{
1815:                 .command = .pong,
1816:                 .cluster = self.cluster,
1817:                 .replica = self.replica,
1818:                 .view = self.view_durable(), // Don't drop pongs while the view is being updated.
1819:                 .release = self.release,
1820:                 // Copy the ping's monotonic timestamp to our pong and add our wall clock sample:
1821:                 .ping_timestamp_monotonic = message.header.ping_timestamp_monotonic,
1822:                 .pong_timestamp_wall = @bitCast(self.clock.realtime()),
1823:             }));
1824: 
1825:             if (message.header.replica < self.replica_count) {
1826:                 const upgrade_targets = &self.upgrade_targets[message.header.replica];
1827:                 if (upgrade_targets.* == null or
1828:                     (upgrade_targets.*.?.checkpoint <= message.header.checkpoint_op and
1829:                         upgrade_targets.*.?.view <= message.header.view))
1830:                 {
1831:                     upgrade_targets.* = .{
1832:                         .checkpoint = message.header.checkpoint_op,
1833:                         .view = message.header.view,
1834:                         .releases = .empty,
1835:                     };
1836: 
1837:                     const releases = ping_message_release_list(message);
1838:                     assert(releases.contains(message.header.release));
1839: 
1840:                     for (releases.slice()) |release| {
1841:                         if (release.value > self.release.value) {
1842:                             upgrade_targets.*.?.releases.push(release);
1843:                         }
1844:                     }
1845:                     if (upgrade_targets.*.?.releases.count > 0) {
1846:                         upgrade_targets.*.?.releases.verify();
1847:                     }
1848:                 }
1849:             }
1850:         }
