1852:         fn on_pong(self: *Replica, message: *const Message.Pong) void {
1853:             assert(message.header.command == .pong);
1854:             if (message.header.replica == self.replica) {
1855:                 log.warn("{}: on_pong: misdirected message (self)", .{self.log_prefix()});
1856:                 return;
1857:             }
1858: 
1859:             // Ignore clocks of standbys.
1860:             if (message.header.replica >= self.replica_count) return;
1861: 
1862:             const m0 = message.header.ping_timestamp_monotonic;
1863:             const t1: i64 = @bitCast(message.header.pong_timestamp_wall);
1864:             const m2 = self.clock.monotonic().ns;
1865: 
1866:             self.clock.learn(message.header.replica, m0, t1, m2);
1867:             if (self.clock.round_trip_time_median_ns()) |rtt_ns| {
1868:                 self.prepare_timeout.set_rtt_ns(rtt_ns);
