1889:         /// When there is free space in the pipeline's prepare queue:
1890:         ///   The primary advances op-number, adds the request to the end of the log, and updates
1891:         ///   the information for this client in the client-table to contain the new request number.
1892:         ///   Then it sends a ⟨Prepare v, m, n, k⟩ message to the other replicas, where v is the
1893:         ///   current view-number, m is the message it received from the client, n is the op-number
1894:         ///   it assigned to the request, and k is the commit-number.
1895:         /// Otherwise, when there is room in the pipeline's request queue:
1896:         ///   The request is queued, and will be dequeued & prepared when the pipeline head commits.
1897:         /// Otherwise, drop the request.
1898:         fn on_request(self: *Replica, message: *Message.Request) void {
1899:             if (self.ignore_request_message(message)) return;
1900: 
1901:             assert(self.status == .normal);
1902:             assert(self.primary());
1903:             assert(self.syncing == .idle);
1904:             assert(self.commit_min == self.commit_max);
1905:             assert(self.commit_max + self.pipeline.queue.prepare_queue.count == self.op);
1906: 
1907:             assert(message.header.command == .request);
1908:             assert(message.header.operation != .reserved);
1909:             assert(message.header.operation != .root);
1910:             assert(message.header.view <= self.view); // The client's view may be behind ours.
