5620:         /// Evicts another entry deterministically, if necessary, to make space for the insert.
5621:         fn client_table_entry_create(self: *Replica, reply: *Message.Reply) void {
5622:             assert(reply.header.command == .reply);
5623:             assert(reply.header.operation == .register);
5624:             assert(reply.header.client > 0);
5625:             assert(reply.header.op == reply.header.commit);
5626:             assert(reply.header.size == @sizeOf(Header) + @sizeOf(vsr.RegisterResult));
5627: 
5628:             const session = reply.header.commit; // The commit number becomes the session number.
5629:             const request = reply.header.request;
5630: 
5631:             // We reserved the `0` commit number for the cluster `.root` operation.
5632:             assert(session > 0);
5633:             assert(request == 0);
5634: 
5635:             // For correctness, it's critical that all replicas evict deterministically:
5636:             // We cannot depend on `HashMap.capacity()` since `HashMap.ensureTotalCapacity()` may
5637:             // change across versions of the Zig std lib. We therefore rely on
5638:             // `constants.clients_max`, which must be the same across all replicas, and must not
5639:             // change after initializing a cluster.
5640:             // We also do not depend on `HashMap.valueIterator()` being deterministic here. However,
5641:             // we do require that all entries have different commit numbers and are iterated.
5642:             // This ensures that we will always pick the entry with the oldest commit number.
5643:             // We also check that a client has only one entry in the hash map (or it's buggy).
5644:             const clients = self.client_sessions.count();
5645:             assert(clients <= constants.clients_max);
5646:             if (clients == constants.clients_max) {
5647:                 const evictee = self.client_sessions.evictee();
5648:                 self.client_sessions.remove(evictee);
5649: 
5650:                 assert(self.client_sessions.count() == constants.clients_max - 1);
5651: 
5652:                 log.warn("{}: client_table_entry_create: clients={}/{} evicting client={}", .{
5653:                     self.log_prefix(),
5654:                     clients,
5655:                     constants.clients_max,
5656:                     evictee,
5657:                 });
5658: 
5659:                 if (self.event_callback) |hook| {
5660:                     hook(self, .{ .client_evicted = evictee });
5661:                 }
5662:             }
5663: 
5664:             log.debug("{}: client_table_entry_create: write (client={} session={} request={})", .{
5665:                 self.log_prefix(),
5666:                 reply.header.client,
5667:                 session,
5668:                 request,
5669:             });
5670: 
5671:             // Any duplicate .register requests should have received the same session number if the
5672:             // client table entry already existed, or been dropped if a session was being committed:
5673:             const reply_slot = self.client_sessions.put(session, reply.header);
5674:             assert(self.client_sessions.count() <= constants.clients_max);
5675: 
5676:             self.client_replies.write_reply(reply_slot, reply, .commit);
5677:         }
